              quotedPhrases: ['payment due', 'credit card bill'], // These DON'T exist in email
              keywords: ['payment', 'credit'],
              reasoning: 'Contains payment and credit references',
            },
          },
        },
      };

      mockCreate.mockResolvedValueOnce({
        choices: [{ message: { content: JSON.stringify(responseWithFakeEvidence) } }],
        usage: { totalTokens: 180 },
      });

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(result.evidenceValidation.invalidPhrases).toContain('payment due');
      expect(result.evidenceValidation.invalidPhrases).toContain('credit card bill');
      expect(result.evidenceValidation.fabricationDetected).toBe(true);
    });
  });

  // Helper function to create large objects for testing
  function createLargeObject(targetSize: number): Record<string, unknown> {
    const baseObject: Record<string, unknown> = {};
    let currentSize = 0;
    let counter = 0;

    while (currentSize < targetSize) {
      const data = `large_data_item_${counter}_${'x'.repeat(100)}`;
      baseObject[`field_${counter}`] = data;
      currentSize = JSON.stringify(baseObject).length;
      counter++;
    }

    return baseObject;
  }

  // Mock semantic intent for testing
  const mockSemanticIntent = {
    primaryPurpose: 'notification' as const,
    actionRequired: 'view' as const,
    urgencyLevel: 'medium' as const,
  };

  describe('Security Enhancements and Robustness', () => {
    it('should prevent stack overflow with deeply nested objects', async () => {
      // Create a deeply nested object that would cause stack overflow
      const deepObj: Record<string, unknown> = {};
      let current = deepObj;
      for (let i = 0; i < 100; i++) {
        // 100 levels deep
        current.nested = { level: i, nullValue: null };
        current = current.nested as Record<string, unknown>;
      }

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      // Should not throw stack overflow error
      const result = await aiFeatureExtractionStage(mockEmail, mockSession, deepObj, {}, mockConfig);

      expect(result.featureExtraction).toBeDefined();
    });

    it('should handle circular references without infinite loops', async () => {
      // Create object with circular reference
      const objA: Record<string, unknown> = { name: 'A' };
      const objB: Record<string, unknown> = { name: 'B', parent: objA };
      objA.child = objB; // Circular reference

      const circularObj = {
        root: objA,
        other: 'data',
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      // Should not hang or throw circular reference error
      const result = await aiFeatureExtractionStage(mockEmail, mockSession, circularObj, {}, mockConfig);

      expect(result.featureExtraction).toBeDefined();
    });

    it('should track performance metrics for large object processing', async () => {
      const consoleSpy = jest.spyOn(console, 'warn').mockImplementation();

      const largeObj = createLargeObject(150000); // Very large object (>100KB)

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      const result = await aiFeatureExtractionStage(mockEmail, mockSession, largeObj, {}, mockConfig);

      expect(result.featureExtraction).toBeDefined();
      expect(result.processingDurationMs).toBeGreaterThan(0);

      // Should log memory usage warning for large objects
      expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Large object detected'));

      consoleSpy.mockRestore();
    });

    it('should prevent template injection with nested braces', async () => {
      const maliciousEmail = {
        ...mockEmail,
        subject: 'Attack {{evil}} template injection',
        bodyPlain: 'More {{nested}} {{attacks}} here',
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      await aiFeatureExtractionStage(
        maliciousEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      const calledArgs = mockCreate.mock.calls[0][0];
      const userMessage = calledArgs.messages[1].content;

      // Nested braces should be sanitized to brackets
      expect(userMessage).toContain('[evil]');
      expect(userMessage).toContain('[nested]');
      expect(userMessage).toContain('[attacks]');
      expect(userMessage).not.toContain('{{');
      expect(userMessage).not.toContain('}}');
    });

    it('should handle JSON strings without breaking them during sanitization', async () => {
      const candidatesWithJson = {
        validJson: '{"key": "value", "nested": {"prop": "data"}}',
        regularField: 'normal text with {template} chars',
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      await aiFeatureExtractionStage(mockEmail, mockSession, candidatesWithJson, mockDetectedAttributes, mockConfig);

      const calledArgs = mockCreate.mock.calls[0][0];
      const userMessage = calledArgs.messages[1].content;

      // JSON should be preserved (even if escaped)
      // When JSON is embedded in JSON, quotes are properly escaped
      expect(userMessage).toContain('\\"key\\"'); // JSON key preserved (escaped)
      expect(userMessage).toContain('\\"value\\"'); // JSON value preserved (escaped)
      // Template-like syntax in JSON values is preserved (not sanitized) because it's valid JSON
      expect(userMessage).toContain('{template}'); // Template chars preserved in JSON context
    });

    it('should limit compaction depth to prevent excessive recursion', async () => {
      // Create an object with excessive nesting
      const veryDeepObj: Record<string, unknown> = { data: 'root' };
      let current = veryDeepObj;
      for (let i = 0; i < 20; i++) {
        // 20 levels deep
        current.deep = { level: i, nullValue: null, empty: [] };
        current = current.deep as Record<string, unknown>;
      }

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: mockSemanticIntent,
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { totalTokens: 50 },
      });

      // Should complete without hanging or excessive processing time
      const startTime = Date.now();
      const result = await aiFeatureExtractionStage(mockEmail, mockSession, veryDeepObj, {}, mockConfig);
      const endTime = Date.now();

      expect(result.featureExtraction).toBeDefined();
      expect(endTime - startTime).toBeLessThan(5000); // Should complete within 5 seconds
    });
  });
});

